#define TABLE_SIZE 100
#define EMPTY -1

int ht_keys[TABLE_SIZE];
int ht_vals[TABLE_SIZE];

int hash(int key) {
    return ((key % TABLE_SIZE) + TABLE_SIZE) % TABLE_SIZE;
}

void put(int key, int val) {
    int idx = hash(key);
    while (ht_keys[idx] != EMPTY && ht_keys[idx] != key)
        idx = (idx + 1) % TABLE_SIZE;
    ht_keys[idx] = key;
    ht_vals[idx] = val;
}

int get(int key) {
    int idx = hash(key);
    while (ht_keys[idx] != EMPTY) {
        if (ht_keys[idx] == key) return ht_vals[idx];
        idx = (idx + 1) % TABLE_SIZE;
    }
    return -1;
}

int main() {
    memset(ht_keys, EMPTY, sizeof(ht_keys));
    put(10, 100);
    put(20, 200);
    put(30, 300);
    printf("%d\n", get(20));
    return 0;
}

