int nums[] = {2, 7, 11, 15};
int target = 9, n = 4;
int seen[1001];
memset(seen, -1, sizeof(seen));

for (int i = 0; i < n; i++) {
    int complement = target - nums[i];
    if (complement >= 0 && complement <= 1000 && seen[complement] != -1) {
        printf("[%d, %d]\n", seen[complement], i);
        break;
    }
    seen[nums[i]] = i;
}
// [0, 1]

